public bool AuthenticateUser(string username, string password)
{
    var principalContext = new PrincipalContext(ContextType.Domain, "your_domain");
    using (var userPrincipal = UserPrincipal.FindByIdentity(principalContext, username))
    {
        if (userPrincipal != null && userPrincipal.IsAccountLockedOut)
