        }
    }

    return true;
}

private static bool VerifyPassword(DirectoryEntry user, string password)
{
    using (var searcher = new DirectorySearcher(user))
    {
        searcher.SearchScope = SearchScope.Subtree;
        searcher.Filter = $"(&(objectClass=krb5principal)(sAMAccountName={user.Properties["sAMAccountName"][0]}))";

        var principal = searcher.FindOne() as DirectoryEntry;
        if (principal == null) return false;

        object passwordValue;
        if (!principal.Invoke("GetPassword", out passwordValue)) return false;

        var encryptedPassword = new SecureString();
        foreach (char c in password.ToCharArray()) encryptedPassword.AppendChar(c);

        return CryptographicEngine.ComparePassword(passwordValue, encryptedPassword);
